func calculateCumulativeCost(exp models.Experiment, currentLevel int) int {
	cost := 0
	for i := 0; i < currentLevel && i < len(exp.Levels); i++ {
		cost += exp.Levels[i].Cost
	}
	return cost
}

func max(a, b int) int {
	if a > b {
		return a
	}
	return b
}

